#nullable enable // autogenerated

using MVZ2.GameContent.Bosses;
using MVZ2.GameContent.Pickups;
using MVZ2.GameContent.ProgressBars;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Level;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Entities;
using PVZEngine.Level;
using UnityEngine;

namespace MVZ2.GameContent.Stages
{
    public class LockedChestStageBehaviour : BossStageBehaviour
    {
        public LockedChestStageBehaviour(StageDefinition stageDef) : base(stageDef)
        {
        }
        public override void PostWave(LevelEngine level, int wave)
        {
            base.PostWave(level, wave);
            //if (wave <= 10)
            //    return;
            //if (!level.HasBuff<RedDragonStageBuff>())
            //{
            //    level.AddBuff<RedDragonStageBuff>();
            //}
        }
        protected override void FinalWaveUpdate(LevelEngine level)
        {
            base.FinalWaveUpdate(level);
            var lastEnemy = level.GetFirstAliveEnemy();
            if (lastEnemy != null)
            {
                level.SetLastEnemyPosition(lastEnemy.Position);
            }
        }
        protected override void AfterFinalWaveUpdate(LevelEngine level)
        {
            base.AfterFinalWaveUpdate(level);
            TransitionUpdate(level);
        }
        private void TransitionUpdate(LevelEngine level)
        {
            if (level.EntityExists(e => e.Type == EntityTypes.BOSS && e.IsHostileEntity() && !e.IsDead))
            {
                // Boss出现
                level.WaveState = VanillaLevelStates.STATE_BOSS_FIGHT;
                level.SetProgressBarToBoss(VanillaProgressBarID.lockedChest);
                return;
            }

            if (!level.EntityExists(e => e.IsEntityOf(VanillaPickupID.lockedChestPickup)))
            {
                var lastEnemyPosition = level.GetLastEnemyPosition();
                Vector3 position;
                if (lastEnemyPosition.x <= LevelPositions.GetBorderX(false))
                {
                    var x = level.GetEnemySpawnX();
                    var z = level.GetEntityLaneZ(Mathf.CeilToInt(level.GetMaxLaneCount() * 0.5f));
                    var y = level.GetGroundY(x, z);
                    position = new Vector3(x, y, z);
                }
                else
                {
                    position = lastEnemyPosition;
                }
                LockedChestPickup.Produce(level, position);
            }
        }
        protected override void BossFightWaveUpdate(LevelEngine level)
        {
            base.BossFightWaveUpdate(level);
            // Boss战斗
            // 如果有Boss存活，不停生成怪物。
            // 如果不存在Boss，或者所有Boss死亡，进入BOSS后阶段。
            if (level.EntityExists(e => e.Type == EntityTypes.BOSS && e.IsHostileEntity() && !e.IsDead))
            {
                RunBossWave(level);
            }
            else
            {
                level.WaveState = VanillaLevelStates.STATE_AFTER_BOSS;
                level.StopMusic();

                if (level.IsRerun || !level.IsAdventure())
                {
                    // 生成通关掉落物。
                    var boss = level.FindFirstEntity(VanillaBossID.lockedChest);
                    Vector3 position;
                    if (boss != null)
                    {
                        position = boss.Position;
                    }
                    else
                    {
                        var x = level.GetLawnCenterX();
                        var z = level.GetLawnCenterZ();
                        var y = level.GetGroundY(x, z);
                        position = new Vector3(x, y, z);
                    }
                    ClearPickup.Produce(level, position);
                }
            }
        }
        protected override void AfterBossWaveUpdate(LevelEngine level)
        {
            base.AfterBossWaveUpdate(level);
            ClearEnemies(level);


            if (!level.IsAdventure() || level.IsRerun)
                return;
            if (level.IsCleared)
                return;

            if (level.EntityExists(e => e.Type == EntityTypes.BOSS && e.IsHostileEntity() && !e.IsDead))
            {
                // BOSS回来则重新进入boss战。
                level.WaveState = VanillaLevelStates.STATE_BOSS_FIGHT;
                return;
            }
            // 有未死亡的BOSS时不结束。
            if (level.EntityExists(e => e.Type == EntityTypes.BOSS && e.IsHostileEntity() && e.IsDead))
                return;
            // 有上锁的箱子的掉落物也不结束。
            if (level.EntityExists(VanillaPickupID.lockedChestPickup))
                return;
            // 隐藏UI，关闭输入
            level.ResetHeldItem();
            level.SetUIAndInputDisabled(true);
            level.Clear();
        }
    }
}
